export function nextGeneration(liveCells: Cell[]): Cell[] {
  const live = new Set(liveCells.map(([x, y]) => key(x, y)));
  const neighbors = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const k = key(nx, ny);
        const entry = neighbors.get(k);
        if (entry) {
          entry.count++;
        } else {
          neighbors.set(k, { cell: [nx, ny], count: 1 });
        }
      }
    }
  }

  const next: Cell[] = [];
  for (const [k, { cell, count }] of neighbors) {
    if (count === 3 || (count === 2 && live.has(k))) {
      next.push(cell);
    }
  }
  return next;
}
